function solve(nums: number[]): number {
    const n = nums.length;
    const totalMask = (1 << n) - 1;
    let totalXOR = 0;
    for (const num of nums) {
        totalXOR ^= num;
    }
    let best = 0;
    for (let maskB = 0; maskB <= totalMask; maskB++) {
        let andB: number = 0;
        let xorB = 0;
        let countB = 0;
        for (let i = 0; i < n; i++) {
            if (maskB & (1 << i)) {
                countB++;
                xorB ^= nums[i];
            }
        }
        if (countB === 0) {
            andB = 0;
        } else {
            andB = -1;
            for (let i = 0; i < n; i++) {
                if (maskB & (1 << i)) {
                    andB &= nums[i];
                }
            }
        }
        const maskR = totalMask ^ maskB;
        const arrR: number[] = [];
        for (let i = 0; i < n; i++) {
            if (maskR & (1 << i)) {
                arrR.push(nums[i]);
            }
        }
        const TR = totalXOR ^ xorB;
        let xors = new Set<number>();
        xors.add(0);
        for (const num of arrR) {
            const newXors = new Set<number>(xors);
            for (const x of xors) {
                newXors.add(x ^ num);
            }
            xors = newXors;
        }
        let maxValR = 0;
        for (const x of xors) {
            const value = x + (TR ^ x);
            if (value > maxValR) {
                maxValR = value;
            }
        }
        const candidate = andB + maxValR;
        if (candidate > best) {
            best = candidate;
        }
    }
    return best;
}
```

